import React, { useEffect, useState } from "react";
import axios from "axios";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid, ResponsiveContainer } from "recharts";

function IndianStockDetails({ symbol }) {
  const [stockData, setStockData] = useState(null);
  const [error, setError] = useState("");
  

  useEffect(() => {
    async function fetchData() {
      try {
        const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
        setStockData(res.data);
      } catch (e) {
        console.error(e);
        setError("Failed to fetch stock data");
      }
    }
    fetchData();
  }, [symbol]);

  if (error) {
    return <p style={{ color: "red" }}>{error}</p>;
  }

  if (!stockData) {
    return <p>Loading...</p>;
  }

  const historicalData = stockData.historical?.indicators?.quote?.[0];
  const timestamps = stockData.historical?.timestamp || [];

  const chartData = timestamps.map((time, i) => ({
    date: new Date(time * 1000).toLocaleDateString(),
    close: historicalData?.close?.[i] || null,
  }));

  return (
    <div style={{ padding: "20px", maxWidth: "1000px", margin: "auto", fontFamily: "Arial" }}>
      <h1>{stockData.name} ({stockData.symbol})</h1>
      <h2 style={{ color: "#333" }}>
        â‚ą{stockData.price?.toFixed(2)}{" "}
        <span style={{ color: stockData.change > 0 ? "green" : "red" }}>
          ({stockData.change?.toFixed(2)} / {stockData.percentChange?.toFixed(2)}%)
        </span>
      </h2>

      {/* Core Metrics */}
      <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", marginTop: "20px" }}>
        {stockData.peRatio && (
          <Metric label="PE Ratio" value={stockData.peRatio.toFixed(2)} />
        )}
        {stockData.eps && (
          <Metric label="EPS" value={stockData.eps.toFixed(2)} />
        )}
        {stockData.roe && (
          <Metric label="ROE" value={(stockData.roe * 100).toFixed(2) + "%"} />
        )}
        {stockData.roce && (
          <Metric label="ROCE" value={(stockData.roce * 100).toFixed(2) + "%"} />
        )}
        {stockData.bookValue && (
          <Metric label="Book Value" value={`â‚ą${stockData.bookValue.toFixed(2)}`} />
        )}
        {stockData.dividendYield && (
          <Metric label="Dividend Yield" value={(stockData.dividendYield * 100).toFixed(2) + "%"} />
        )}
        {stockData.fiftyTwoWeekHigh && (
          <Metric label="52W High" value={`â‚ą${stockData.fiftyTwoWeekHigh.toFixed(2)}`} />
        )}
        {stockData.fiftyTwoWeekLow && (
          <Metric label="52W Low" value={`â‚ą${stockData.fiftyTwoWeekLow.toFixed(2)}`} />
        )}
        {stockData.marketCap && (
          <Metric label="Market Cap" value={`â‚ą${(stockData.marketCap / 1e7).toFixed(2)} Cr`} />
        )}
      </div>

      {/* Pros and Cons */}
      {stockData.pros?.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h3>Pros</h3>
          <ul>
            {stockData.pros.map((item, i) => (
              <li key={i}>{item}</li>
            ))}
          </ul>
        </div>
      )}

      {stockData.cons?.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h3>Cons</h3>
          <ul>
            {stockData.cons.map((item, i) => (
              <li key={i}>{item}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Balance Sheet */}
      {stockData.balanceSheet?.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h3>Balance Sheet</h3>
          <table border="1" cellPadding="5" cellSpacing="0">
            <thead>
              <tr>
                <th>Year</th>
                <th>Total Assets</th>
                <th>Total Liabilities</th>
              </tr>
            </thead>
            <tbody>
              {stockData.balanceSheet.map((row, i) => (
                <tr key={i}>
                  <td>{new Date(row.endDate).getFullYear()}</td>
                  <td>â‚ą{(row.totalAssets / 1e7).toFixed(2)} Cr</td>
                  <td>â‚ą{(row.totalLiabilities / 1e7).toFixed(2)} Cr</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Profit & Loss */}
      {stockData.incomeStatement?.length > 0 && (
        <div style={{ marginTop: "30px" }}>
          <h3>Profit and Loss</h3>
          <table border="1" cellPadding="5" cellSpacing="0">
            <thead>
              <tr>
                <th>Year</th>
                <th>Total Revenue</th>
                <th>Net Income</th>
              </tr>
            </thead>
            <tbody>
              {stockData.incomeStatement.map((row, i) => (
                <tr key={i}>
                  <td>{new Date(row.endDate).getFullYear()}</td>
                  <td>â‚ą{(row.totalRevenue / 1e7).toFixed(2)} Cr</td>
                  <td>â‚ą{(row.netIncome / 1e7).toFixed(2)} Cr</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Historical Chart */}
      {chartData?.length > 0 && (
        <div style={{ marginTop: "40px" }}>
          <h3>Price Trend (Last 6 months)</h3>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={chartData}>
              <CartesianGrid stroke="#eee" strokeDasharray="5 5" />
              <XAxis dataKey="date" />
              <YAxis />
              <Tooltip />
              <Line type="monotone" dataKey="close" stroke="#8884d8" strokeWidth={2} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

function Metric({ label, value }) {
  return (
    <div style={{
      background: "#f8f8f8",
      padding: "10px",
      borderRadius: "8px",
      width: "200px",
    }}>
      <h4 style={{ margin: "0 0 5px 0" }}>{label}</h4>
      <p style={{ margin: 0, fontWeight: "bold", fontSize: "16px" }}>{value}</p>
    </div>
  );
